param([Parameter(Mandatory=$true)][string]$RunDirectory,[Parameter(Mandatory=$true)][string]$Destination,[Parameter(Mandatory=$true)][string]$BatchIdentity,[Parameter(Mandatory=$true)][string]$RunIdentifier)
$ErrorActionPreference='Stop';$target='execution';$csv='nora_phase2_execution_tester_v1.csv';$required=@('compile.json','execution.json','compile.log','tester-journal.log','tester.htm','completion-marker.json','failure-marker.json',$csv)
function FileHash($p){(Get-FileHash -LiteralPath $p -Algorithm SHA256).Hash.ToLowerInvariant()}
if(Test-Path $Destination){throw 'existing destination'};$tmp=$Destination+'.tmp-'+[guid]::NewGuid().ToString('N')
try{New-Item -ItemType Directory $tmp|Out-Null;foreach($name in $required){$source=Join-Path $RunDirectory $name;if(!(Test-Path $source -PathType Leaf)){throw "missing collected file: $name"};Copy-Item $source (Join-Path $tmp $name)};$execution=Get-Content (Join-Path $tmp 'execution.json') -Raw|ConvertFrom-Json;if($execution.run_identifier -ne $RunIdentifier -or $execution.final_batch_identity -ne $BatchIdentity -or $execution.collection_state -ne 'complete'){throw 'execution binding'};$complete=Get-Content (Join-Path $tmp 'completion-marker.json') -Raw|ConvertFrom-Json;$failure=Get-Content (Join-Path $tmp 'failure-marker.json') -Raw|ConvertFrom-Json;if(!$complete.present -or $failure.present){throw 'marker state'};$inventory=@();foreach($name in $required){$f=Join-Path $tmp $name;$inventory+=@{path=$name;size=(Get-Item $f).Length;sha256=FileHash $f}};$inventory|ConvertTo-Json|Set-Content (Join-Path $tmp 'returned_inventory.json') -Encoding utf8;$inventoryHash=FileHash (Join-Path $tmp 'returned_inventory.json');$manifest=[ordered]@{schema_version='nora.execution_returned_package_v2';target_identifier=$target;batch_identity=$BatchIdentity;run_identifier=$RunIdentifier;host_symbol=$execution.host_symbol;timeframe=$execution.timeframe;execution_packet_identity=$execution.execution_packet_identity;compiler_output_identity=$execution.compiler_output_identity;ex5_sha256=$execution.ex5_sha256;completion_marker_present=$true;failure_marker_present=$false;returned_inventory_sha256=$inventoryHash;files=@($required+@('returned_inventory.json'))};$bytes=[Text.Encoding]::UTF8.GetBytes(($manifest|ConvertTo-Json -Depth 8 -Compress));$hasher=[Security.Cryptography.SHA256]::Create();$digest=$hasher.ComputeHash($bytes);$hasher.Dispose();$manifest.returned_package_identity=[BitConverter]::ToString($digest).Replace('-','').ToLowerInvariant();$manifest|ConvertTo-Json -Depth 8|Set-Content (Join-Path $tmp 'returned_result_manifest.json') -Encoding utf8;Move-Item $tmp $Destination;Write-Output $Destination}catch{Remove-Item $tmp -Recurse -Force -ErrorAction SilentlyContinue;throw}
